// Classify incident severity based on alert data
const body = $input.first().json.body || $input.first().json;

const alert = {
  source: body.source || 'unknown',
  type: body.type || body.alertType || 'general',
  title: body.title || body.summary || 'Untitled Alert',
  description: body.description || body.details || '',
  contractAddress: body.contractAddress || null,
  chain: body.chain || null,
  detectedAt: body.detectedAt || body.timestamp || new Date().toISOString(),
  rawPayload: body
};

// Severity classification rules
let severity = 'LOW';
let severityScore = 0;
const type = alert.type.toLowerCase();
const desc = alert.description.toLowerCase();

// Critical indicators
if (
  type.includes('exploit') ||
  type.includes('drain') ||
  type.includes('reentrancy') ||
  desc.includes('funds at risk') ||
  desc.includes('active exploit') ||
  desc.includes('flash loan attack')
) {
  severity = 'CRITICAL';
  severityScore = 95;
}
// High indicators
else if (
  type.includes('vulnerability') ||
  type.includes('unauthorized') ||
  desc.includes('access control') ||
  desc.includes('privilege escalation') ||
  desc.includes('oracle manipulation')
) {
  severity = 'HIGH';
  severityScore = 75;
}
// Medium indicators
else if (
  type.includes('anomaly') ||
  type.includes('suspicious') ||
  desc.includes('unusual pattern') ||
  desc.includes('compliance violation')
) {
  severity = 'MEDIUM';
  severityScore = 50;
}
// Low — everything else
else {
  severity = 'LOW';
  severityScore = 25;
}

const incidentId = `INC-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;

return [{
  json: {
    incidentId,
    severity,
    severityScore,
    ...alert,
    classifiedAt: new Date().toISOString(),
    status: 'OPEN',
    timeline: [
      {
        event: 'incident_created',
        timestamp: new Date().toISOString(),
        actor: 'system',
        details: `Incident auto-classified as ${severity}`
      }
    ]
  }
}];

// Non-critical: Standard notification
const incident = $input.first().json;

const severityEmoji = {
  HIGH: '🟠',
  MEDIUM: '🟡',
  LOW: '🟢'
};

const emoji = severityEmoji[incident.severity] || '📋';

const msg = `${emoji} *Incident Alert — ${incident.severity}*\n\n` +
  `🔑 ID: \`${incident.incidentId}\`\n` +
  `⚡ Severity: ${incident.severity} (${incident.severityScore}/100)\n` +
  `📋 Type: ${incident.type}\n` +
  `📝 ${incident.title}\n\n` +
  `${incident.description.substring(0, 300)}\n\n` +
  (incident.contractAddress ? `🔑 Contract: \`${incident.contractAddress}\`\n` : '') +
  `\n🕐 Detected: ${incident.detectedAt}`;

return [{ json: { ...incident, notificationMessage: msg, channels: ['team'] } }];

// Record timeline event for ticket creation
const incident = $('Classify Severity').first().json;
const ticket = $input.first().json;

const timeline = incident.timeline || [];
timeline.push({
  event: 'ticket_created',
  timestamp: new Date().toISOString(),
  actor: 'system',
  details: `Ticket created: ${ticket.ticketId || ticket.id || 'N/A'}`
});

timeline.push({
  event: 'team_notified',
  timestamp: new Date().toISOString(),
  actor: 'system',
  details: `Team notified via Telegram`
});

return [{
  json: {
    incidentId: incident.incidentId,
    ticketId: ticket.ticketId || ticket.id,
    severity: incident.severity,
    status: 'INVESTIGATING',
    timeline,
    updatedAt: new Date().toISOString()
  }
}];
